class Solution {
public:
    int countLargestGroup(int n) {
        vector<int> sum(10, 0);
        for (int i = 1; i <= n; ++i) {
            int s = 0;
            int num = i;
            while (num > 0) {
                s += num % 10;
                num /= 10;
            }
            sum[s]++;
        }
        int max_size = 0;
        for (int i = 0; i < 10; ++i) {
            max_size = max(max_size, sum[i]);
        }
        return count(sum.begin(), sum.end(), max_size);
    }
};
